     1→import { useState, useEffect, useCallback } from 'react';
     2→import {
     3→  Card,
     4→  CardBody,
     5→  CardTitle,
     6→  CardHeader,
     7→  CardExpandableContent,
     8→  Label,
     9→  Flex,
    10→  FlexItem,
    11→  Content,
    12→  Progress,
    13→  ProgressMeasureLocation,
    14→  Divider,
    15→  Spinner,
    16→  Alert,
    17→  Button,
    18→  Icon,
    19→  Split,
    20→  SplitItem,
    21→} from '@patternfly/react-core';
    22→import {
    23→  InProgressIcon,
    24→  ClockIcon,
    25→  CodeBranchIcon,
    26→  SyncAltIcon,
    27→} from '@patternfly/react-icons';
    28→import { invoke } from '@tauri-apps/api/core';
    29→import { motion } from 'motion/react';
    30→import { useHarnessWatcher } from '../hooks/useHarnessWatcher';
    31→
    32→interface TaskSummary {
    33→  backlog: number;
    34→  todo: number;
    35→  doing: number;
    36→  review: number;
    37→  qa: number;
    38→  done: number;
    39→  total: number;
    40→}
    41→
    42→interface SessionInfo {
    43→  id: string;
    44→  started_at: string;
    45→  title?: string;
    46→}
    47→
    48→interface GitInfo {
    49→  hash: string;
    50→  message: string;
    51→  author: string;
    52→  date: string;
    53→}
    54→
    55→interface ActiveTask {
    56→  id: string;
    57→  title: string;
    58→  status: string;
    59→}
    60→
    61→interface ProgressCardProps {
    62→  projectPath: string;
    63→  onRefresh?: () => void;
    64→}
    65→
    66→// Execute harness CLI command via Tauri shell
    67→async function runHarnessCommand(projectPath: string, args: string[]): Promise<string> {
    68→  try {
    69→    const result = await invoke<string>('run_harness_command', {
    70→      projectPath,
    71→      args,
    72→    });
    73→    return result;
    74→  } catch (error) {
    75→    console.error('Failed to run harness command:', error);
    76→    throw error;
    77→  }
    78→}
    79→
    80→// Parse task summary from harness status --json
    81→function parseTaskSummary(json: string): TaskSummary | null {
    82→  try {
    83→    const data = JSON.parse(json);
    84→    if (data.tasks) {
    85→      return {
    86→        backlog: data.tasks.backlog || 0,
    87→        todo: data.tasks.todo || 0,
    88→        doing: data.tasks.doing || 0,
    89→        review: data.tasks.review || 0,
    90→        qa: data.tasks.qa || 0,
    91→        done: data.tasks.done || 0,
    92→        total: data.tasks.total || 0,
    93→      };
    94→    }
    95→    return null;
    96→  } catch {
    97→    return null;
    98→  }
    99→}
   100→
   101→// Parse session info from harness session current --json
   102→function parseSessionInfo(json: string): SessionInfo | null {
   103→  try {
   104→    const data = JSON.parse(json);
   105→    if (data.id) {
   106→      return {
   107→        id: data.id,
   108→        started_at: data.started_at,
   109→        title: data.title,
   110→      };
   111→    }
   112→    return null;
   113→  } catch {
   114→    return null;
   115→  }
   116→}
   117→
   118→// Format relative time
   119→function formatRelativeTime(isoDate: string): string {
   120→  const date = new Date(isoDate);
   121→  const now = new Date();
   122→  const diff = now.getTime() - date.getTime();
   123→  const minutes = Math.floor(diff / 60000);
   124→  const hours = Math.floor(diff / 3600000);
   125→
   126→  if (minutes < 1) return 'Just now';
   127→  if (minutes < 60) return `${minutes}m ago`;
   128→  if (hours < 24) return `${hours}h ago`;
   129→  return date.toLocaleDateString();
   130→}
   131→
   132→export function ProgressCard({
   133→  projectPath,
   134→  onRefresh,
   135→}: ProgressCardProps): React.JSX.Element {
   136→  const [isExpanded, setIsExpanded] = useState(true);
   137→  const [isLoading, setIsLoading] = useState(true);
   138→  const [error, setError] = useState<string | null>(null);
   139→  const [taskSummary, setTaskSummary] = useState<TaskSummary | null>(null);
   140→  const [session, setSession] = useState<SessionInfo | null>(null);
   141→  const [gitInfo, setGitInfo] = useState<GitInfo | null>(null);
   142→  const [activeTasks, setActiveTasks] = useState<ActiveTask[]>([]);
   143→
   144→  const fetchData = useCallback(async () => {
   145→    setIsLoading(true);
   146→    setError(null);
   147→
   148→    try {
   149→      // Get task summary via harness status --json
   150→      try {
   151→        const statusJson = await runHarnessCommand(projectPath, ['status', '--format', 'json']);
   152→        const summary = parseTaskSummary(statusJson);
   153→        if (summary) {
   154→          setTaskSummary(summary);
   155→        }
   156→      } catch (e) {
   157→        console.error('Failed to get status:', e);
   158→      }
   159→
   160→      // Get current session via harness session current --json
   161→      try {
   162→        const sessionJson = await runHarnessCommand(projectPath, ['session', 'current', '--format', 'json']);
   163→        const sessionData = parseSessionInfo(sessionJson);
   164→        setSession(sessionData);
   165→      } catch {
   166→        setSession(null);
   167→      }
   168→
   169→      // Get active (doing) tasks
   170→      try {
   171→        const tasksJson = await runHarnessCommand(projectPath, ['task', 'list', '--status', 'Doing', '--format', 'json']);
   172→        const tasks = JSON.parse(tasksJson);
   173→        if (Array.isArray(tasks)) {
   174→          setActiveTasks(tasks.slice(0, 3).map((t: { id: string; title: string; status: string }) => ({
   175→            id: t.id,
   176→            title: t.title,
   177→            status: t.status,
   178→          })));
   179→        }
   180→      } catch {
   181→        setActiveTasks([]);
   182→      }
   183→
   184→      // Get git info
   185→      try {
   186→        const gitResult = await invoke<string>('get_git_info', { projectPath });
   187→        if (gitResult) {
   188→          const parsed = JSON.parse(gitResult);
   189→          setGitInfo(parsed);
   190→        }
   191→      } catch {
   192→        setGitInfo(null);
   193→      }
   194→    } catch (e) {
   195→      setError('Failed to load project status');
   196→      console.error(e);
   197→    } finally {
   198→      setIsLoading(false);
   199→    }
   200→  }, [projectPath]);
   201→
   202→  useEffect(() => {
   203→    fetchData();
   204→  }, [fetchData]);
   205→
   206→  // Auto-refresh when .harness files change (F008)
   207→  useHarnessWatcher({
   208→    projectPath,
   209→    onChange: fetchData,
   210→    enabled: !!projectPath,
   211→  });
   212→
   213→  const handleRefresh = useCallback(() => {
   214→    fetchData();
   215→    onRefresh?.();
   216→  }, [fetchData, onRefresh]);
   217→
   218→  const completionPercent = taskSummary
   219→    ? Math.round((taskSummary.done / Math.max(taskSummary.total, 1)) * 100)
   220→    : 0;
   221→
   222→  return (
   223→    <Card isExpanded={isExpanded}>
   224→      <CardHeader
   225→        onExpand={() => setIsExpanded(!isExpanded)}
   226→        isToggleRightAligned
   227→        toggleButtonProps={{
   228→          'aria-label': isExpanded ? 'Collapse progress' : 'Expand progress',
   229→        }}
   230→        actions={{
   231→          actions: (
   232→            <Button
   233→              variant="plain"
   234→              aria-label="Refresh"
   235→              onClick={handleRefresh}
   236→              isDisabled={isLoading}
   237→            >
   238→              <SyncAltIcon />
   239→            </Button>
   240→          ),
   241→        }}
   242→      >
   243→        <CardTitle>
   244→          <Flex alignItems={{ default: 'alignItemsCenter' }} gap={{ default: 'gapSm' }}>
   245→            <FlexItem>Project Progress</FlexItem>
   246→            {taskSummary && (
   247→              <FlexItem>
   248→                <Label color="blue" isCompact>
   249→                  {taskSummary.done}/{taskSummary.total}
   250→                </Label>
   251→              </FlexItem>
   252→            )}
   253→          </Flex>
   254→        </CardTitle>
   255→      </CardHeader>
   256→      <CardExpandableContent>
   257→        <CardBody>
   258→          {isLoading ? (
   259→            <Flex justifyContent={{ default: 'justifyContentCenter' }}>
   260→              <Spinner size="lg" />
   261→            </Flex>
   262→          ) : error ? (
   263→            <Alert variant="warning" title="Unable to load progress" isInline>
   264→              {error}
   265→            </Alert>
   266→          ) : (
   267→            <motion.div
   268→              initial={{ opacity: 0 }}
   269→              animate={{ opacity: 1 }}
   270→              transition={{ duration: 0.2 }}
   271→            >
   272→              {/* Progress bar */}
   273→              {taskSummary && (
   274→                <>
   275→                  <Progress
   276→                    value={completionPercent}
   277→                    title="Completion"
   278→                    measureLocation={ProgressMeasureLocation.top}
   279→                    label={`${completionPercent}% complete`}
   280→                  />
   281→
   282→                  {/* Status breakdown */}
   283→                  <Flex
   284→                    gap={{ default: 'gapSm' }}
   285→                    style={{ marginTop: 16, marginBottom: 16, flexWrap: 'wrap' }}
   286→                  >
   287→                    {taskSummary.backlog > 0 && (
   288→                      <FlexItem>
   289→                        <Label color="grey" isCompact>
   290→                          Backlog: {taskSummary.backlog}
   291→                        </Label>
   292→                      </FlexItem>
   293→                    )}
   294→                    {taskSummary.todo > 0 && (
   295→                      <FlexItem>
   296→                        <Label color="blue" isCompact>
   297→                          Todo: {taskSummary.todo}
   298→                        </Label>
   299→                      </FlexItem>
   300→                    )}
   301→                    {taskSummary.doing > 0 && (
   302→                      <FlexItem>
   303→                        <Label color="orange" isCompact>
   304→                          Doing: {taskSummary.doing}
   305→                        </Label>
   306→                      </FlexItem>
   307→                    )}
   308→                    {taskSummary.review > 0 && (
   309→                      <FlexItem>
   310→                        <Label color="purple" isCompact>
   311→                          Review: {taskSummary.review}
   312→                        </Label>
   313→                      </FlexItem>
   314→                    )}
   315→                    {taskSummary.qa > 0 && (
   316→                      <FlexItem>
   317→                        <Label color="teal" isCompact>
   318→                          QA: {taskSummary.qa}
   319→                        </Label>
   320→                      </FlexItem>
   321→                    )}
   322→                    <FlexItem>
   323→                      <Label color="green" isCompact>
   324→                        Done: {taskSummary.done}
   325→                      </Label>
   326→                    </FlexItem>
   327→                  </Flex>
   328→                </>
   329→              )}
   330→
   331→              {/* Active tasks */}
   332→              {activeTasks.length > 0 && (
   333→                <>
   334→                  <Divider style={{ marginBottom: 16 }} />
   335→                  <Content component="h4" style={{ marginBottom: 8 }}>
   336→                    <Icon status="warning" size="sm">
   337→                      <InProgressIcon />
