/**
 * useHarnessWatcher - Hook for watching .harness directory changes (F008)
 *
 * Watches the .harness directory for file changes and triggers
 * a callback when changes are detected. Uses debouncing on the
 * Rust side (500ms) to avoid excessive updates.
 */

import { useEffect, useCallback, useRef } from 'react';
import { invoke, listen } from '../lib/rpc';

type UnlistenFn = () => void;

export interface HarnessChangeEvent {
  /** The project path being watched */
  project_path: string;
  /** Type of change: "db", "config", or "unknown" */
  change_type: 'db' | 'config' | 'unknown';
  /** The file that changed (relative to .harness/) */
  file: string;
}

export interface UseHarnessWatcherOptions {
  /** Project path to watch */
  projectPath: string;
  /** Callback when changes are detected */
  onChange?: (event: HarnessChangeEvent) => void;
  /** Whether to enable watching (default: true) */
  enabled?: boolean;
}

/**
 * Hook to watch a project's .harness directory for changes
 *
 * @example
 * ```tsx
 * useHarnessWatcher({
 *   projectPath: '/path/to/project',
 *   onChange: (event) => {
 *     console.log('Change detected:', event.file);
 *     refetchData();
 *   },
 * });
 * ```
 */
export function useHarnessWatcher({
  projectPath,
  onChange,
  enabled = true,
}: UseHarnessWatcherOptions): void {
  const isWatchingRef = useRef(false);
  const onChangeRef = useRef(onChange);

  // Keep onChange ref up to date
  useEffect(() => {
    onChangeRef.current = onChange;
  }, [onChange]);

  // Check if we're in Tauri context
  const isTauri = useCallback(() => {
    return typeof window !== 'undefined' && '__TAURI__' in window;
  }, []);

  useEffect(() => {
    if (!enabled || !projectPath || !isTauri()) {
      return;
    }

    let unlistenFn: UnlistenFn | null = null;

    const startWatching = async () => {
      try {
        // Start watching
        await invoke('harness_watch_start', { projectPath });
        isWatchingRef.current = true;

        // Listen for change events
        unlistenFn = await listen<HarnessChangeEvent>('harness-change', (event) => {
          // Only handle events for this project
          if (event.payload.project_path === projectPath) {
            onChangeRef.current?.(event.payload);
          }
        });
      } catch (error) {
        console.error('Failed to start harness watcher:', error);
      }
    };

    startWatching();

    return () => {
      // Cleanup: stop watching and remove listener
      if (isWatchingRef.current) {
        invoke('harness_watch_stop', { projectPath }).catch((e) =>
          console.error('Failed to stop harness watcher:', e)
        );
        isWatchingRef.current = false;
      }
      if (unlistenFn) {
        unlistenFn();
      }
    };
  }, [projectPath, enabled, isTauri]);
}

export default useHarnessWatcher;

