import { useCallback, useEffect, useState } from 'react';

/**
 * Hook to track window focus state.
 *
 * When the window loses focus, the app should dim slightly to indicate
 * it's not the active window (like native macOS apps).
 *
 * Usage:
 * ```tsx
 * const { isFocused } = useWindowFocus();
 *
 * return (
 *   <div className={isFocused ? '' : 'window-unfocused'}>
 *     ...
 *   </div>
 * );
 * ```
 */
export function useWindowFocus() {
  const [isFocused, setIsFocused] = useState(true);

  const handleFocus = useCallback(() => {
    setIsFocused(true);
    document.documentElement.classList.remove('window-unfocused');
  }, []);

  const handleBlur = useCallback(() => {
    setIsFocused(false);
    document.documentElement.classList.add('window-unfocused');
  }, []);

  useEffect(() => {
    // Check initial state
    if (document.hasFocus()) {
      handleFocus();
    } else {
      handleBlur();
    }

    // Listen for focus/blur events
    window.addEventListener('focus', handleFocus);
    window.addEventListener('blur', handleBlur);

    // Also listen for Tauri window focus events if available
    let unlisten: (() => void) | undefined;

    async function setupTauriListener() {
      try {
        // Dynamic import to avoid errors in browser mode
        const { listen } = await import('@tauri-apps/api/event');
        unlisten = await listen<boolean>('window-focus', (event) => {
          if (event.payload) {
            handleFocus();
          } else {
            handleBlur();
          }
        });
      } catch {
        // Not in Tauri context, ignore
      }
    }

    setupTauriListener();

    return () => {
      window.removeEventListener('focus', handleFocus);
      window.removeEventListener('blur', handleBlur);
      unlisten?.();
    };
  }, [handleFocus, handleBlur]);

  return { isFocused };
}

/**
 * CSS styles to apply when window is unfocused.
 * Import and add to your global CSS:
 *
 * ```css
 * .window-unfocused {
 *   // Styles defined in index.css
 * }
 * ```
 */
export const UNFOCUSED_STYLES = `
/* Window unfocused state - dim UI elements */
.window-unfocused {
  --window-opacity: 0.7;
}

/* Dim selection highlights when unfocused */
.window-unfocused .tab-active,
.window-unfocused [aria-selected="true"],
.window-unfocused .pf-m-selected {
  background-color: var(--pf-t--global--background--color--secondary--default, #e0e0e0);
}

/* Reduce contrast of text when unfocused */
.window-unfocused .pf-v6-c-card,
.window-unfocused .pf-v6-c-panel {
  opacity: var(--window-opacity, 0.7);
}

/* Keep important elements visible */
.window-unfocused .keep-visible {
  opacity: 1;
}
`;

export default useWindowFocus;

