"run_harness_command" => {
    let project_path = args["projectPath"].as_str().ok_or("Missing 'projectPath' argument")?;
    let cmd_args: Vec<String> = args["args"]
        .as_array()
        .map(|arr| {
            arr.iter()
                .filter_map(|v| v.as_str().map(String::from))
                .collect()
        })
        .unwrap_or_default();

    // Get the harness binary path
    let current_exe = std::env::current_exe().map_err(|e| e.to_string())?;
    let harness_path = current_exe.parent()
        .ok_or("Cannot get executable directory")?
        .join("harness");

    let output = std::process::Command::new(&harness_path)
        .current_dir(project_path)
        .args(&cmd_args)
        .output()
        .map_err(|e| format!("Failed to run harness command: {}", e))?;

    if output.status.success() {
        let stdout = String::from_utf8_lossy(&output.stdout).to_string();
        Ok(serde_json::Value::String(stdout))
    } else {
        let stderr = String::from_utf8_lossy(&output.stderr).to_string();
        Err(format!("Harness command failed: {}", stderr))
    }
}

"get_git_info" => {
    let project_path = args["projectPath"].as_str().ok_or("Missing 'projectPath' argument")?;

    let output = std::process::Command::new("git")
        .current_dir(project_path)
        .args(["log", "-1", "--format=%H%n%s%n%an%n%ai"])
        .output()
        .map_err(|e| format!("Failed to run git: {}", e))?;

    if output.status.success() {
        let stdout = String::from_utf8_lossy(&output.stdout);
        let lines: Vec<&str> = stdout.trim().lines().collect();
        if lines.len() >= 4 {
            let info = serde_json::json!({
                "hash": lines[0],
                "message": lines[1],
                "author": lines[2],
                "date": lines[3]
            });
            Ok(serde_json::Value::String(info.to_string()))
        } else {
            Err("Invalid git output".to_string())
        }
    } else {
        Err("Git command failed".to_string())
    }
}

