/**
 * Set the dev bridge token
 */
export function setDevBridgeToken(newToken: string): void {
  token = newToken;
  localStorage.setItem("hq-dev-bridge-token", newToken);
}

/**
 * Check if connection is currently ready
 */
export function isConnectionReady(): boolean {
  if (isTauri()) return true;
  return connectionReady && ws !== null && ws.readyState === WebSocket.OPEN;
}

/**
 * Wait for the dev bridge connection to be ready
 * @param timeoutMs Maximum time to wait (default: 10000ms)
 * @returns Promise that resolves to true if connected, false if timeout/failed
 */
export async function waitForConnection(timeoutMs = 10000): Promise<boolean> {
  // Tauri is always ready
  if (isTauri()) return true;

  // Already connected
  if (connectionReady && ws && ws.readyState === WebSocket.OPEN) {
    return true;
  }

  // Start connection if not already
  const connectPromise = connectDevBridge();

  // Wait for connection with timeout
  return new Promise((resolve) => {
    const timeout = setTimeout(() => {
      // Remove from waiting list on timeout
      const idx = connectionReadyResolvers.indexOf(resolve);
      if (idx >= 0) connectionReadyResolvers.splice(idx, 1);
      resolve(false);
    }, timeoutMs);

    // Add to waiting list
    connectionReadyResolvers.push((ready) => {
      clearTimeout(timeout);
      resolve(ready);
    });

    // Also check the connect promise result
    connectPromise.then((connected) => {
      if (connected) {
        clearTimeout(timeout);
        resolve(true);
      }
    });
  });
}

/**
 * Sleep for a given duration
 */
function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Unified invoke function - works in Tauri and browser contexts
 * Includes automatic retry with exponential backoff for connection issues
 */
export async function invoke<T>(
  cmd: string,
  args: Record<string, unknown> = {}
): Promise<T> {
  // Tauri native context
  if (isTauri()) {
    const { invoke: tauriInvoke } = await import("@tauri-apps/api/core");
    return tauriInvoke<T>(cmd, args);
  }

  // Browser context - use dev bridge with retry logic
  let lastError: Error | null = null;

  for (let attempt = 0; attempt < MAX_INVOKE_RETRIES; attempt++) {
    // Wait for connection with exponential backoff
    const waitTime = attempt === 0 ? 2000 : INVOKE_RETRY_DELAY_MS * Math.pow(2, attempt);
    const connected = await waitForConnection(waitTime);

