                    variant="warning"
                    title="Invalid Project"
                    actionClose={
                      <AlertActionCloseButton onClose={() => setError(null)} />
                    }
                  >
                    {error}
                  </Alert>
                </motion.div>
              </StackItem>
            )}
          </AnimatePresence>

          {/* Browse Button */}
          <StackItem>
            <Button
              variant="primary"
              icon={<FolderOpenIcon />}
              onClick={handleBrowse}
              isLoading={isLoading}
              isDisabled={isLoading}
              isBlock
            >
              {isLoading ? 'Opening...' : 'Browse for Folder...'}
            </Button>
          </StackItem>

