          <StackItem>
            <Content component="h3">
              Recent Projects
              {validatingProjects && (
                <Spinner size="sm" style={{ marginLeft: 8 }} />
              )}
            </Content>
          </StackItem>

          <StackItem>
            {recentProjects.length === 0 ? (
              <EmptyState
                titleText="No recent projects"
                headingLevel="h4"
                icon={FolderIcon}
              >
                <EmptyStateBody>
                  Open a project folder to get started. Projects with a .harness
                  directory will be shown here for quick access.
                </EmptyStateBody>
                <EmptyStateFooter>
                  <EmptyStateActions>
                    <Button
                      variant="primary"
                      icon={<PlusCircleIcon />}
                      onClick={handleBrowse}
                    >
                      Open Project
                    </Button>
                  </EmptyStateActions>
                </EmptyStateFooter>
              </EmptyState>
            ) : (
              <Stack hasGutter>
                <AnimatePresence>
                  {recentProjects.map((project, index) => (
                    <StackItem key={project.path}>
                      <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: 20 }}
                        transition={{ delay: index * 0.05 }}
                      >
                        <Card
                          isClickable
                          isSelectable
                          onClick={() => handleSelectRecent(project)}
                          style={{
                            opacity: project.isValid === false ? 0.5 : 1,
                          }}
                        >
                          <CardBody>
                            <Split hasGutter>
                              <SplitItem>
                                <Icon
                                  status={project.isValid === false ? 'warning' : 'info'}
                                  size="lg"
                                >
                                  <FolderIcon />
                                </Icon>
                              </SplitItem>
                              <SplitItem isFilled>
                                <Content>
                                  <Content component="h4" style={{ marginBottom: 4 }}>
                                    {project.name}
                                  </Content>
                                  <Content
                                    component="small"
                                    style={{
                                      color: 'var(--pf-t--global--text--color--subtle)',
                                      wordBreak: 'break-all',
                                    }}
                                  >
                                    {project.path}
                                  </Content>
                                </Content>
                              </SplitItem>
                              <SplitItem>
                                <Split hasGutter>
                                  <SplitItem>
                                    <Label isCompact color="grey">
                                      {formatRelativeTime(project.lastOpened)}
                                    </Label>
                                  </SplitItem>
                                  {project.isValid === false && (
                                    <SplitItem>
                                      <Label isCompact color="orange">
                                        Invalid
                                      </Label>
                                    </SplitItem>
                                  )}
                                  <SplitItem>
                                    <Button
                                      variant="plain"
                                      aria-label="Remove from recent"
                                      onClick={(e) =>
                                        handleRemoveRecent(e, project.path)
                                      }
                                    >
                                      <TimesIcon />
                                    </Button>
                                  </SplitItem>
                                </Split>
                              </SplitItem>
                            </Split>
                          </CardBody>
                        </Card>
                      </motion.div>
                    </StackItem>
                  ))}
                </AnimatePresence>
              </Stack>
            )}
          </StackItem>
        </Stack>
      </ModalBody>
    </Modal>
  );
}

export default ProjectSelector;

