        if (!isValid) {
          setError(`Selected folder does not contain a .harness directory. Please select a valid Harness project.`);
          setIsLoading(false);
          return;
        }

        const name = getProjectName(selected);
        addToRecentProjects(selected, name);
        onSelectProject(selected, name);
        onClose();
      }
    } catch (e) {
      console.error('Failed to open directory:', e);
      setError('Failed to open folder picker. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }, [onSelectProject, onClose, isDevBridgeMode]);

  // Handle manual path submission (Dev Bridge mode)
  const handleManualPathSubmit = useCallback(async () => {
    if (!manualPath.trim()) {
      setError('Please enter a valid path');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // Wait for connection first
      if (!isTauri()) {
        const connected = await waitForConnection(5000);
        if (!connected) {
          setError('Unable to connect to Dev Bridge. Make sure the app is running with "bun tauri dev".');
          setIsLoading(false);
          return;
        }
      }

      const path = manualPath.trim();

      // Validate it's a harness project
      const isValid = await validateHarnessProject(path);

      if (!isValid) {
        setError(`Path does not contain a .harness directory. Please enter a valid Harness project path.`);
        setIsLoading(false);
        return;
      }

      const name = getProjectName(path);
      addToRecentProjects(path, name);
      onSelectProject(path, name);
      onClose();
    } catch (e) {
      console.error('Failed to validate path:', e);
      setError(`Failed to validate path: ${e instanceof Error ? e.message : 'Unknown error'}`);
    } finally {
      setIsLoading(false);
    }
  }, [manualPath, onSelectProject, onClose]);

  // Handle Enter key on manual input
  const handleManualKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleManualPathSubmit();
    }
  }, [handleManualPathSubmit]);

  // Handle select recent project
  const handleSelectRecent = useCallback(async (project: RecentProject) => {
    setError(null);

    // Re-validate before opening
    const isValid = await validateHarnessProject(project.path);

    if (!isValid) {
      setError(`Project "${project.name}" no longer contains a valid .harness directory.`);
      return;
    }

    addToRecentProjects(project.path, project.name);
    onSelectProject(project.path, project.name);
    onClose();
  }, [onSelectProject, onClose]);

  // Handle remove recent project
  const handleRemoveRecent = useCallback((e: React.MouseEvent, path: string) => {
    e.stopPropagation();
    const updated = removeFromRecentProjects(path);
    setRecentProjects(updated);
  }, []);

  // Format relative time
  const formatRelativeTime = (timestamp: number): string => {
    const diff = Date.now() - timestamp;
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (minutes < 1) return 'Just now';
    if (minutes < 60) return `${minutes}m ago`;
    if (hours < 24) return `${hours}h ago`;
    if (days < 7) return `${days}d ago`;
    return new Date(timestamp).toLocaleDateString();
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      variant={ModalVariant.medium}
      aria-label="Project Selector"
    >
      <ModalHeader title="Open Project" />
      <ModalBody>
        <Stack hasGutter>
          {/* Error Alert */}
          <AnimatePresence>
            {error && (
              <StackItem>
                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  exit={{ opacity: 0, height: 0 }}
                >
                  <Alert
                    variant="warning"
                    title="Invalid Project"
                    actionClose={
                      <AlertActionCloseButton onClose={() => setError(null)} />
                    }
                  >
                    {error}
                  </Alert>
                </motion.div>
              </StackItem>
            )}
          </AnimatePresence>

          {/* Browse Button */}
          <StackItem>
            <Button
              variant="primary"
              icon={<FolderOpenIcon />}
              onClick={handleBrowse}
              isLoading={isLoading}
              isDisabled={isLoading}
              isBlock
            >
              {isLoading ? 'Opening...' : 'Browse for Folder...'}
            </Button>
          </StackItem>

          {/* Recent Projects */}
          <StackItem>
            <Content component="h3">
              Recent Projects
              {validatingProjects && (
                <Spinner size="sm" style={{ marginLeft: 8 }} />
              )}
            </Content>
          </StackItem>

          <StackItem>
            {recentProjects.length === 0 ? (
              <EmptyState
                titleText="No recent projects"
                headingLevel="h4"
                icon={FolderIcon}
              >
                <EmptyStateBody>
                  Open a project folder to get started. Projects with a .harness
                  directory will be shown here for quick access.
                </EmptyStateBody>
                <EmptyStateFooter>
                  <EmptyStateActions>
                    <Button
                      variant="primary"
                      icon={<PlusCircleIcon />}
                      onClick={handleBrowse}
                    >
                      Open Project
                    </Button>
                  </EmptyStateActions>
                </EmptyStateFooter>
              </EmptyState>
            ) : (
              <Stack hasGutter>
                <AnimatePresence>
                  {recentProjects.map((project, index) => (
                    <StackItem key={project.path}>
                      <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: 20 }}
                        transition={{ delay: index * 0.05 }}
                      >
                        <Card
                          isClickable
                          isSelectable
                          onClick={() => handleSelectRecent(project)}
                          style={{
                            opacity: project.isValid === false ? 0.5 : 1,
                          }}
                        >
                          <CardBody>
                            <Split hasGutter>
                              <SplitItem>
                                <Icon
                                  status={project.isValid === false ? 'warning' : 'info'}
                                  size="lg"
                                >
                                  <FolderIcon />
                                </Icon>
                              </SplitItem>
                              <SplitItem isFilled>
                                <Content>
                                  <Content component="h4" style={{ marginBottom: 4 }}>
                                    {project.name}
                                  </Content>
                                  <Content
                                    component="small"
                                    style={{
                                      color: 'var(--pf-t--global--text--color--subtle)',
                                      wordBreak: 'break-all',
                                    }}
                                  >
                                    {project.path}
                                  </Content>
                                </Content>
                              </SplitItem>
                              <SplitItem>
                                <Split hasGutter>
                                  <SplitItem>
                                    <Label isCompact color="grey">
                                      {formatRelativeTime(project.lastOpened)}
                                    </Label>
                                  </SplitItem>
                                  {project.isValid === false && (
                                    <SplitItem>
                                      <Label isCompact color="orange">
                                        Invalid
                                      </Label>
                                    </SplitItem>
                                  )}
                                  <SplitItem>
                                    <Button
                                      variant="plain"
                                      aria-label="Remove from recent"
                                      onClick={(e) =>
                                        handleRemoveRecent(e, project.path)
                                      }
                                    >
                                      <TimesIcon />
                                    </Button>
                                  </SplitItem>
                                </Split>
                              </SplitItem>
                            </Split>
                          </CardBody>
                        </Card>
                      </motion.div>
                    </StackItem>
                  ))}
                </AnimatePresence>
              </Stack>
            )}
          </StackItem>
        </Stack>
      </ModalBody>
    </Modal>
  );
}

export default ProjectSelector;

