                                <Content>
                                  <Content component="h4" style={{ marginBottom: 4 }}>
                                    {project.name}
                                  </Content>
                                  <Content
                                    component="small"
                                    style={{
                                      color: 'var(--pf-t--global--text--color--subtle)',
                                      wordBreak: 'break-all',
                                    }}
                                  >
                                    {project.path}
                                  </Content>
                                </Content>
                              </SplitItem>
                              <SplitItem>
                                <Split hasGutter>
                                  <SplitItem>
                                    <Label isCompact color="grey">
                                      {formatRelativeTime(project.lastOpened)}
                                    </Label>
                                  </SplitItem>
                                  {project.isValid === false && (
                                    <SplitItem>
                                      <Label isCompact color="orange">
                                        Invalid
                                      </Label>
                                    </SplitItem>
                                  )}
                                  <SplitItem>
                                    <Button
                                      variant="plain"
                                      aria-label="Remove from recent"
                                      onClick={(e) =>
                                        handleRemoveRecent(e, project.path)
                                      }
                                    >
                                      <TimesIcon />
                                    </Button>
                                  </SplitItem>
                                </Split>
                              </SplitItem>
                            </Split>
                          </CardBody>
                        </Card>
                      </motion.div>
                    </StackItem>
                  ))}
                </AnimatePresence>
              </Stack>
            )}
          </StackItem>
        </Stack>
      </ModalBody>
    </Modal>
  );
}

export default ProjectSelector;

